import React from 'react';
import Catalog from '../catalog-view';

let GridCatalogs = ({ catalogs, onSelectCatalog }) => {

  return (
    <div>
      <div className="main-section__catalogs">
        {
          catalogs.map(catalog => <Catalog data={catalog} onClick={onSelectCatalog}/>)
        }
      </div>
    </div>
  );
}



export default GridCatalogs;
