import React from 'react';
import Product from '../product-view';

let GridProducts = ({ products, onSelectProduct }) => {

  return (
    <div>
      <div className="main-section__products">
        {
          products.map(product => <Product data={product} onClick={onSelectProduct}/>)
        }
      </div>
    </div>
  );
}



export default GridProducts;
